class UserTOTPManager:
    """Manages TOTP secrets and verification for multiple users."""

    def __init__(self, storage_file='totp_users.json', issuer='MyApp'):
        """
        Initialize the user TOTP manager.

        Args:
            storage_file: Path to JSON file for storing user secrets
            issuer: Name of the issuing service
        """
        self.storage_file = storage_file
        self.issuer = issuer
        self.authenticator = TOTPAuthenticator()
        self.users = self._load_users()

    def _load_users(self):
        """Load user data from storage file."""
        try:
            with open(self.storage_file, 'r') as f:
                return json.load(f)
        except (FileNotFoundError, json.JSONDecodeError):
            return {}

    def _save_users(self):
        """Save user data to storage file."""
        with open(self.storage_file, 'w') as f:
            json.dump(self.users, f, indent=2)

    def register_user(self, user_email):
        """
        Register a new user for TOTP 2FA.

        Args:
            user_email: User's email address

        Returns:
            Dictionary with secret, provisioning URI, and backup codes
        """
        secret = self.authenticator.generate_secret()
        backup_codes = self._generate_backup_codes()

        self.users[user_email] = {
            'secret': secret,
            'enabled': False,  # Not enabled until first verification
            'backup_codes': backup_codes,
            'created_at': time.time(),
            'last_used_counter': None,
        }
        self._save_users()

        provisioning_uri = self.authenticator.get_provisioning_uri(
            secret, user_email, self.issuer
        )

        return {
            'secret': secret,
            'provisioning_uri': provisioning_uri,
            'backup_codes': backup_codes,
        }

    def _generate_backup_codes(self, count=8, length=8):
        """Generate backup recovery codes."""
        codes = []
        for _ in range(count):
            code = base64.b32encode(os.urandom(length)).decode('utf-8')[:length]
            codes.append(code.lower())
        return codes

    def confirm_registration(self, user_email, code):
        """
        Confirm TOTP registration by verifying the first code.

        Args:
            user_email: User's email address
            code: TOTP code from authenticator app

        Returns:
            True if confirmed successfully, False otherwise
        """
        if user_email not in self.users:
            return False

        user = self.users[user_email]
        if self.authenticator.verify_totp(user['secret'], code):
            user['enabled'] = True
            self._save_users()
            return True
        return False

    def verify_code(self, user_email, code):
        """
        Verify a TOTP code for a user.

        Also checks backup codes if TOTP verification fails.

        Args:
            user_email: User's email address
            code: TOTP code or backup code

        Returns:
            Dictionary with verification result and method used
        """
        if user_email not in self.users:
            return {'valid': False, 'reason': 'User not found'}

        user = self.users[user_email]

        if not user.get('enabled'):
            return {'valid': False, 'reason': 'TOTP not enabled for this user'}

        # Try TOTP verification first
        if self.authenticator.verify_totp(user['secret'], code):
            # Replay attack prevention
            current_counter = self.authenticator._get_time_counter()
            last_counter = user.get('last_used_counter')
            if last_counter is not None and current_counter <= last_counter:
                return {'valid': False, 'reason': 'Code already used (replay protection)'}

            user['last_used_counter'] = current_counter
            self._save_users()
            return {'valid': True, 'method': 'totp'}

        # Try backup codes
        normalized_code = code.lower().strip()
        if normalized_code in user.get('backup_codes', []):
            user['backup_codes'].remove(normalized_code)
            self._save_users()
            remaining = len(user['backup_codes'])
            return {
                'valid': True,
                'method': 'backup_code',
                'remaining_backup_codes': remaining,
            }

        return {'valid': False, 'reason': 'Invalid code'}

    def disable_totp(self, user_email, code):
        """
        Disable TOTP for a user (requires valid code).

        Args:
            user_email: User's email address
            code: Current valid TOTP code

        Returns:
            True if disabled successfully
        """
        if user_email not in self.users:
            return False

        user = self.users[user_email]
        if self.authenticator.verify_totp(user['secret'], code):
            del self.users[user_email]
            self._save_users()
            return True
        return False

    def regenerate_backup_codes(self, user_email, code):
        """
        Regenerate backup codes (requires valid TOTP code).

        Args:
            user_email: User's email address
            code: Current valid TOTP code

        Returns:
            New backup codes list or None if verification fails
        """
        if user_email not in self.users:
            return None

        user = self.users[user_email]
        if self.authenticator.verify_totp(user['secret'], code):
            new_codes = self._generate_backup_codes()
            user['backup_codes'] = new_codes
            self._save_users()
            return new_codes
        return None

    def get_user_status(self, user_email):
        """Get TOTP status for a user."""
        if user_email not in self.users:
            return {'registered': False}

        user = self.users[user_email]
        return {
            'registered': True,
            'enabled': user.get('enabled', False),
            'backup_codes_remaining': len(user.get('backup_codes', [])),
            'created_at': user.get('created_at'),
        }


